// Devuelve el mes actual normalizado para reutilizarlo como referencia temporal en configuraciones y vínculos dependientes.
function getCurrentMonthKey() {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
}

// Renderiza renderizar actividad templates sección.
function renderActivityTemplatesSection() {
  // Renderiza las plantillas reutilizables que permiten aplicar configuraciones completas de actividades.
  let cards='';
  S.templates.forEach(t=>{
    cards+=`<div class="tpl-card">
      <div class="tpl-name">${t.name}</div>
      <div class="tpl-desc">${t.desc||''} ? ${t.created}</div>
      <div class="tpl-apply" style="display:flex;gap:6px;margin-top:8px;">
        <button class="btn btn-primary btn-sm" onclick="applyTemplate('${t.id}')">Aplicar</button>
        <button class="btn btn-danger btn-sm" onclick="delTpl('${t.id}')"><i class="ri-delete-bin-line"></i></button>
      </div>
    </div>`;
  });
  return `<div style="margin-bottom:22px;">
    <div style="font-size:12px;font-weight:800;letter-spacing:1px;text-transform:uppercase;color:rgba(255,255,255,.3);margin-bottom:10px;">Plantillas guardadas</div>
    <div class="tpl-grid">${cards}</div>
  </div>`;
}

// Renderiza renderizar actividades config block.
function renderActivitiesConfigBlock(b) {
  // Pinta y refresca un bloque específico con sus actividades, metas, alertas y controles de ajuste.
  const container = document.getElementById('cfg-blocks');
  if(!container) return;
  let el = document.getElementById('cfg-block-'+b);
  if(!el){
    el = document.createElement('div');
    el.id = 'cfg-block-'+b;
    container.appendChild(el);
  }
  const cfg = getGroupCfg(S.activeGroupId)[b];
  const acts = cfg.activities;
  const rawMax = blockRawMax(b);
  const meta = blockMeta(b);
  const diff = round2(rawMax - meta);
  const norm = cfg.normalize !== false;

  let actRows='';
  acts.forEach((a,i)=>{
    actRows+=`<div class="act-row">
      <div class="act-num">${i+1}</div>
      <input class="act-name-inp" value="${a.name}" oninput="handleActNameInput('${b}','${a.id}',this)" onblur="handleActNameBlur('${b}','${a.id}',this)" placeholder="Nombre de actividad">
      <input class="act-pts-inp" type="number" value="${fmtNum(a.pts)}" min="0" max="999" step="0.1" inputmode="decimal" placeholder="Ej. 5.5" title="Puntos (admite decimales)" oninput="updateActPts('${b}','${a.id}',this.value,false)" onblur="updateActPts('${b}','${a.id}',this.value,true)" onchange="updateActPts('${b}','${a.id}',this.value,true)">
      <div style="font-size:10.5px;color:rgba(255,255,255,.35);text-align:center;">pts</div>
      <button onclick="removeActFromBlock('${b}','${a.id}')" style="background:rgba(244,63,94,.1);border:none;border-radius:6px;color:rgba(244,63,94,.7);cursor:pointer;width:26px;height:26px;font-size:13px;display:flex;align-items:center;justify-content:center;transition:var(--t);" onmouseover="this.style.background='rgba(244,63,94,.3)'" onmouseout="this.style.background='rgba(244,63,94,.1)'"><i class="ri-delete-bin-line"></i></button>
    </div>`;
  });

  // alert class
  const alertCls = diff===0?'pa-ok':diff>0?'pa-over':'pa-under';
  const alertMsg = diff===0
    ? 'Total coincide con la meta'
    : diff>0 ? `Te sobran ${fmtNum(diff)} pts sobre la meta`
    : `Faltan ${fmtNum(Math.abs(diff))} pts para la meta`;

  // slider value
  const sliderVal = acts.length;

  el.innerHTML=`
  <div class="block-section">
    <div class="block-hdr">
      <div class="block-name">
        <div class="block-dot" style="background:${BCOLOR[b]};"></div>
        ${BICON[b]} ${BNAME[b]}
      </div>
      <div class="block-controls">
        <span style="font-size:11px;color:rgba(255,255,255,.4);">Meta:</span>
        <input class="meta-inp" type="number" value="${meta}" min="1" max="999" onchange="updateMeta('${b}',this.value)" title="Puntaje meta del bloque">
        <span class="meta-label">pts meta</span>
        <button onclick="addActToBlock('${b}')" style="background:rgba(51,149,255,.15);border:1px solid rgba(51,149,255,.3);color:var(--aqua);border-radius:7px;padding:5px 11px;cursor:pointer;font-family:inherit;font-size:12px;font-weight:700;transition:var(--t);" onmouseover="this.style.background='rgba(51,149,255,.28)'" onmouseout="this.style.background='rgba(51,149,255,.15)'">+ Act.</button>
        <button onclick="autoAdjustBlock('${b}')" style="background:rgba(245,158,11,.15);border:1px solid rgba(245,158,11,.3);color:var(--amber);border-radius:7px;padding:5px 11px;cursor:pointer;font-family:inherit;font-size:12px;font-weight:700;transition:var(--t);" onmouseover="this.style.background='rgba(245,158,11,.28)'" onmouseout="this.style.background='rgba(245,158,11,.15)'">Auto</button>
      </div>
    </div>

    <div style="padding:10px 18px 4px;display:flex;align-items:center;gap:14px;">
      <span style="font-size:12px;color:rgba(255,255,255,.4);">Cantidad de actividades:</span>
      <input type="range" min="1" max="15" value="${sliderVal}" style="flex:1;max-width:200px;" oninput="sliderChangeCount('${b}',this.value)" onchange="sliderChangeCount('${b}',this.value)">
      <span style="font-size:14px;font-weight:800;color:#fff;min-width:20px;">${sliderVal}</span>
    </div>

    <div class="act-table-wrap">
      <div style="display:grid;grid-template-columns:36px 1fr 90px 90px 32px;gap:8px;padding:4px 0 8px;">
        <div></div>
        <div style="font-size:10px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;color:rgba(255,255,255,.25);">Nombre</div>
        <div style="font-size:10px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;color:rgba(255,255,255,.25);text-align:center;">Puntos</div>
        <div></div><div></div>
      </div>
      ${actRows || `<div style="padding:16px 0;text-align:center;color:rgba(255,255,255,.3);font-size:13px;">Sin actividades ? <span style="cursor:pointer;color:var(--aqua);" onclick="addActToBlock('${b}')">+ Agregar</span></div>`}
    </div>

    <div class="progress-section">
      <div class="prog-header">
        <span class="prog-label">Total de puntos del bloque</span>
        <span class="prog-values" style="color:${diff===0?'#34d399':diff>0?'#fb7185':'#fbbf24'};">${fmtNum(rawMax)} / ${fmtNum(meta)} pts</span>
      </div>
      <div class="prog-bar">
        <div class="prog-fill" id="pf-${b}" style="width:${meta>0?Math.min(rawMax/meta*100,100):0}%;background:${diff===0?'#10b981':diff>0?'var(--rose)':'var(--amber)'}"></div>
      </div>
      <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px;">
        <span class="prog-alert ${alertCls}">${alertMsg}</span>
      </div>
    </div>

    <div class="sw-row">
      <div>
        <div class="sw-label">Normalizar a escala meta</div>
        <div class="sw-sub">Si activo: convierte el total real del bloque a la escala meta (ej. siempre sobre 100)</div>
      </div>
      <label class="switch">
        <input type="checkbox" ${norm?'checked':''} onchange="toggleNormalize('${b}',this.checked)">
        <div class="sw-track"></div>
        <div class="sw-thumb"></div>
      </label>
    </div>
  </div>`;
}

// Recalcula el bloque visible después de cualquier cambio para mantener puntajes, sliders y totales en sincronía.
function renderActivitiesConfigProgress(b) {
  // Recalcula el bloque visible después de cualquier cambio para mantener puntajes, sliders y totales en sincronía.
  renderActivitiesConfigBlock(b);
}

// Gestiona slider change count.
function sliderChangeCount(b, val) {
  // Ajusta la cantidad de actividades de un bloque y limpia notas/evaluaciones si se reducen filas.
  const n = parseInt(val)||1;
  const current = getGroupCfg(S.activeGroupId)[b].activities;
  if(n > current.length){
    for(let i=current.length;i<n;i++){
      current.push({
        id:uid(), name:`Actividad ${i+1}`, courseId:S.activeGroupId, periodId:S.activePeriodId, pts:20, tipo:'', fecha:'', desc:'', producto:'',
        instrumentId:null, instrumentIds:[], instrumentHistory:[]
      });
    }
  } else if(n < current.length){
    // Remove from end, clean notes
    const removed = current.splice(n);
    removed.forEach(a=>{
      Object.keys(S.notas).forEach(eid=>{ if(S.notas[eid]) delete S.notas[eid][a.id]; });
      S.evaluations = S.evaluations.filter(e=>!(e.activityId===a.id && (e.periodId||'P1')===S.activePeriodId));
    });
  }
  persist(); renderActivitiesConfigBlock(b);
}
/* ------------------------- MATRIX ------------------------- */
// Renderiza la matriz consolidada del grupo activo y muestra accesos rápidos cuando faltan estudiantes o actividades.
RENDERS.matriz = function(c) {
  const ests = studentsInGroup(S.activeGroupId);
  console.debug('[EduGest][matriz]', {activeCourseId: S.activeCourseId||S.activeGroupId, filteredStudents: ests.length});
  if(ests.length===0||totalActs()===0){
    c.innerHTML=`<div class="card"><div class="empty"><div class="ei"><i class="ri-inbox-2-line"></i></div><div class="et">Matriz vacía</div>
      <div class="es">${ests.length===0?'Registra estudiantes en el grupo seleccionado.':'Configura actividades en los bloques.'}</div>
      <div style="display:flex;gap:10px;flex-wrap:wrap;justify-content:center;">
        ${ests.length===0?`<button class="btn btn-outline" onclick="go('estudiantes')">Ir a estudiantes</button>`:''}
        ${totalActs()===0?`<button class="btn btn-primary" onclick="go('config')">Ir a configuración</button>`:''}
      </div>
    </div></div>`;
    return;
  }

  const cfg = getGroupCfg(S.activeGroupId);
  const blockActs = {};
  BLOCKS.forEach(b => blockActs[b] = cfg[b].activities);
  // Gestiona block total100.
  const blockTotal100 = (estId, b) => {
    const meta = blockMeta(b, S.activeGroupId) || 100;
    const score = studentBlockScore(estId, b, S.activeGroupId);
    if (meta <= 0) return 0;
    return Math.round((score / meta) * 100);
  };

  let th1 = `<tr><th class="st" rowspan="2">Estudiante</th>`;
  BLOCKS.forEach(b=>{
    const n = blockActs[b].length;
    if(n>0) th1+=`<th class="bh ${b}" colspan="${n+1}">${BICON[b]} ${BNAME[b]}<br><span style="font-size:10px;font-weight:500;opacity:.8;">TOTAL BLOQUE (0-100)</span></th>`;
  });
  th1+=`<th class="bh tot" colspan="2">Final</th></tr>`;

  let th2='<tr>';
  BLOCKS.forEach(b=>{
    blockActs[b].forEach(a=>{
      th2+=`<th class="ah ${b}" title="${a.name}">${a.name.length>10?a.name.slice(0,10)+'...':a.name}<br><span style="font-size:9px;">${fmtNum(a.pts)}pt</span></th>`;
    });
    if(blockActs[b].length>0){
      th2+=`<th class="ah tot">TOTAL BLOQUE<br><span style="font-size:9px;">/100 pts</span></th>`;
    }
  });
  th2+=`<th class="ah tot">PROMEDIO<br><span style="font-size:9px;">(0-100)</span></th><th class="ah tot">% FINAL</th></tr>`;

  let tbody='<tbody>';
  ests.forEach(e=>{
    tbody+=`<tr><td class="sc">${e.nombre} ${e.apellido}</td>`;
    const totals = [];
    BLOCKS.forEach(b=>{
      blockActs[b].forEach(a=>{
        const raw=(S.notas[e.id]||{})[a.id]||0;
        const cls=scoreClass(raw,a.pts);
        const shown = raw===0 ? '0' : (raw||'?');
        tbody+=`<td style="padding:5px;text-align:center;" title="Se califica desde Actividades -> Evaluar (Instrumentos).">
          <span class="si ${cls}" style="display:inline-flex;align-items:center;justify-content:center;cursor:not-allowed;">${shown}</span>
        </td>`;
      });
      if(blockActs[b].length>0){
        const tb = blockTotal100(e.id,b);
        totals.push(tb);
        const cls=scoreClass(tb,100);
        tbody+=`<td class="bt ${cls}" style="color:${BCOLOR[b]};">${tb}</td>`;
      }
    });
    const avg = totals.length ? Math.round(totals.reduce((s,v)=>s+v,0)/4) : 0;
    tbody+=`<td class="ft">${avg}</td>`;
    tbody+=`<td class="ft">${avg}%</td>`;
    tbody+='</tr>';
  });
  tbody+='</tbody>';

  c.innerHTML=`<div class="card"><div class="ch"><span class="ch-title">Vista matriz - ${getGroupLabel(S.activeGroupId)} ? ${periodName()}</span></div><div class="mtx-wrap"><table class="mtx"><thead>${th1}${th2}</thead>${tbody}</table></div></div>`;
};
// Genera un nombre de archivo consistente para todas las exportaciones del panel de reportes.
function reportExportBaseName() {
  const group = getGroupLabel(S.activeGroupId) || 'grupo';
  const period = periodName() || 'periodo';
  const raw = `${group}-${period}`;
  const slug = normTxt(raw).replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
  return `reporte-${slug || 'general'}`;
}
// Extrae una tabla renderizada del DOM a una matriz plana para reutilizar la misma base en Excel, PDF y Word.
function reportExtractTableMatrix(tableEl) {
  if (!tableEl) return [];
  return Array.from(tableEl.querySelectorAll('tr')).map((row) =>
    Array.from(row.querySelectorAll('th,td')).map((cell) =>
      String(cell.textContent || '').replace(/\s+/g, ' ').trim()
    )
  ).filter((row) => row.length > 0);
}
// Convierte la matriz intermedia en una tabla HTML portable para exportaciones imprimibles y editables.
function reportMatrixToHtmlTable(matrix) {
  if (!matrix.length) return '<table><tbody><tr><td>Sin datos</td></tr></tbody></table>';
  const [head, ...rows] = matrix;
  const thead = `<thead><tr>${head.map((cell)=>`<th>${escapeHtml(cell)}</th>`).join('')}</tr></thead>`;
  const tbody = `<tbody>${rows.map((row)=>`<tr>${row.map((cell)=>`<td>${escapeHtml(cell)}</td>`).join('')}</tr>`).join('')}</tbody>`;
  return `<table>${thead}${tbody}</table>`;
}
// Construye el documento HTML que sirve como fuente única de exportación para los distintos formatos.
function reportBuildExportHtml(title, calMatrix, annualMatrix) {
  const safeTitle = escapeHtml(title || 'Reporte');
  const calTable = reportMatrixToHtmlTable(calMatrix);
  const annualTable = reportMatrixToHtmlTable(annualMatrix);
  return `<!doctype html><html><head><meta charset="utf-8"><title>${safeTitle}</title>
  <style>
    body{font-family:Arial,sans-serif;color:#111827;margin:24px;}
    h1{font-size:20px;margin:0 0 4px;}
    .sub{font-size:12px;color:#6b7280;margin:0 0 14px;}
    h2{font-size:15px;margin:16px 0 8px;color:#1f2937;}
    table{width:100%;border-collapse:collapse;margin-bottom:12px;}
    th,td{border:1px solid #d1d5db;padding:8px;font-size:12px;line-height:1.35;text-align:left;}
    th{background:#f3f4f6;font-weight:700;}
  </style></head><body>
    <h1>${safeTitle}</h1>
    <p class="sub">${escapeHtml(getGroupLabel(S.activeGroupId) || 'Sin grupo')} ? ${escapeHtml(periodName())}</p>
    <h2>Tabla de calificaciones</h2>
    ${calTable}
    <h2>Resumen anual por estudiante</h2>
    ${annualTable}
  </body></html>`;
}
// Exporta el reporte visible a Excel usando la misma estructura de tablas que el usuario ve en pantalla.
function reportDownloadExcel() {
  const calTable = document.querySelector('.reportes-stack .tbl');
  const annualTable = document.querySelector('.annual-report-table');
  const calMatrix = reportExtractTableMatrix(calTable);
  const annualMatrix = reportExtractTableMatrix(annualTable);
  if (!calMatrix.length && !annualMatrix.length) { toast('No hay datos para exportar', true); return; }
  const html = reportBuildExportHtml('Reporte AulaBase', calMatrix, annualMatrix);
  const blob = new Blob(['\ufeff', html], { type: 'application/vnd.ms-excel;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${reportExportBaseName()}.xls`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1200);
}
// Abre una versión imprimible del reporte para que el navegador la convierta en PDF desde la ventana emergente.
async function reportDownloadPdf() {
  const calTable = document.querySelector('.reportes-stack .tbl');
  const annualTable = document.querySelector('.annual-report-table');
  const calMatrix = reportExtractTableMatrix(calTable);
  const annualMatrix = reportExtractTableMatrix(annualTable);
  if (!calMatrix.length && !annualMatrix.length) { toast('No hay datos para exportar', true); return; }
  try {
    const htmlBase = reportBuildExportHtml('Reporte AulaBase', calMatrix, annualMatrix);
    const html = htmlBase.replace(
      '</body>',
      `<script>
        window.addEventListener('load', function () {
          setTimeout(function () {
            try { window.focus(); window.print(); } catch (_) {}
          }, 180);
        });
      </script></body>`
    );
    const blob = new Blob([html], { type: 'text/html;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const win = window.open(url, '_blank');
    if (!win) {
      URL.revokeObjectURL(url);
      toast('Tu navegador bloqueó la ventana de impresión. Habilita pop-ups para este sitio.', true);
      return;
    }
    setTimeout(() => URL.revokeObjectURL(url), 60000);
  } catch (error) {
    console.error('[EduGest][reportes] Error exportando PDF', error);
    toast('No se pudo generar el PDF', true);
  }
}
// Genera una copia editable del reporte en formato Word a partir del HTML consolidado.
function reportDownloadWord() {
  const calTable = document.querySelector('.reportes-stack .tbl');
  const annualTable = document.querySelector('.annual-report-table');
  const calMatrix = reportExtractTableMatrix(calTable);
  const annualMatrix = reportExtractTableMatrix(annualTable);
  if (!calMatrix.length && !annualMatrix.length) { toast('No hay datos para exportar', true); return; }
  const html = reportBuildExportHtml('Reporte AulaBase', calMatrix, annualMatrix);
  const blob = new Blob(['\ufeff', html], { type: 'application/msword' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${reportExportBaseName()}.doc`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1200);
}
// Pinta el panel de reportes con exportaciones, promedios por bloque, detalle por estudiante y resumen anual.
RENDERS.reportes = function(c) {
  const ests = studentsInGroup(S.activeGroupId);
  const chartCols = BLOCKS.map(b=>({
    lbl: BNAME[b],
    val: globalBlockAvg(b) ?? 0,
    meta: blockMeta(b),
    color: BCOLOR[b],
    norm: doNormalize(b),
  }));

  let barH='<div class="chart-bars">';
  chartCols.forEach(col=>{
    const pct = col.meta>0 ? Math.min(col.val/col.meta*100,100) : 0;
    barH+=`<div class="bar-col">
      <div class="bar-val">${col.val||'?'}</div>
      <div class="bar-rect" style="height:${pct*1.3}px;background:${col.color};opacity:.85;"></div>
      <div class="bar-lbl">${col.lbl}${col.norm?'*':''}</div>
    </div>`;
  });
  barH+='</div><div style="font-size:11px;color:var(--mute);margin-top:8px;">* = normalizado a escala meta</div>';

  // student table
  let stbl='';
  if(ests.length===0) stbl=`<div class="empty"><div class="ei"><i class="ri-inbox-2-line"></i></div><div class="es">Sin estudiantes en el grupo seleccionado</div></div>`;
  else {
    stbl=`<div style="overflow-x:auto;"><table class="tbl"><thead><tr><th>Estudiante</th>
      ${BLOCKS.map(b=>`<th style="text-align:center;">${BICON[b]} ${BNAME[b]}<br><span style="font-weight:400;text-transform:none;font-size:10px;">/${blockMeta(b)}</span></th>`).join('')}
      <th style="text-align:center;">Final</th></tr></thead><tbody>`;
    ests.forEach(e=>{
      const scores=BLOCKS.map(b=>studentBlockScore(e.id,b));
      const fin=studentFinal(e.id);
      const {l,c}=getGrade(fin);
      stbl+=`<tr><td style="font-weight:600;">${e.nombre} ${e.apellido}</td>
        ${scores.map((s,i)=>`<td style="text-align:center;font-weight:700;">${s}</td>`).join('')}
        <td style="text-align:center;"><span class="gb ${c}">${fin ?? '—'}</span></td></tr>`;
    });
    stbl+='</tbody></table></div>';
  }
  let annual='';
  if (ests.length===0) {
    annual = `<div class="empty"><div class="es">Sin estudiantes para resumen anual</div></div>`;
  } else {
    annual = `<div style="overflow-x:auto;"><table class="tbl annual-report-table"><thead><tr><th>Estudiante</th><th>P1</th><th>P2</th><th>P3</th><th>P4</th>${BLOCKS.map((blockId) => `<th>${BNAME[blockId]}</th>`).join('')}<th>Promedio anual</th><th>% anual</th></tr></thead><tbody>`;
    ests.forEach(e=>{
      const vals = ['P1','P2','P3','P4'].map(pid=>studentFinal(e.id, S.activeGroupId, pid));
      const annualBlocks = BLOCKS.map((blockId) => studentAnnualBlockAverage(e.id, blockId, S.activeGroupId));
      const fin = studentAnnualFinal(e.id, S.activeGroupId);
      annual += `<tr><td style="font-weight:600;">${e.nombre} ${e.apellido}</td>
        ${vals.map(v=>`<td style="text-align:center;">${v===null?'?':v}</td>`).join('')}
        ${annualBlocks.map(v=>`<td style="text-align:center;">${v===null?'?':fmtNum(v)}</td>`).join('')}
        <td style="text-align:center;font-weight:700;">${fin===null?'?':fin}</td>
        <td style="text-align:center;font-weight:700;">${fin===null?'?':`${fin}%`}</td>
      </tr>`;
    });
    annual += `</tbody></table></div>`;
  }

  c.innerHTML=`
  <div class="g3" style="margin-bottom:18px;">
    <div class="card cp" style="cursor:pointer;text-align:center;" onclick="reportDownloadExcel()"><div style="margin-bottom:8px;"><img src="/assets/icons/logoexcel.png" alt="Excel" style="width:40px;height:40px;object-fit:contain;"></div><div style="font-weight:700;">Excel</div><div style="font-size:12px;color:var(--mute);">Matriz completa</div></div>
    <div class="card cp" style="cursor:pointer;text-align:center;" onclick="reportDownloadPdf()"><div style="margin-bottom:8px;"><img src="/assets/icons/logopdf.png" alt="PDF" style="width:40px;height:40px;object-fit:contain;"></div><div style="font-weight:700;">PDF</div><div style="font-size:12px;color:var(--mute);">Informe listo</div></div>
    <div class="card cp" style="cursor:pointer;text-align:center;" onclick="reportDownloadWord()"><div style="margin-bottom:8px;"><img src="/assets/icons/logoword.png" alt="Word" style="width:40px;height:40px;object-fit:contain;"></div><div style="font-weight:700;">Word</div><div style="font-size:12px;color:var(--mute);">Editable</div></div>
  </div>
  <div id="reportes-export-root">
  <div class="reportes-stack">
    <div class="card"><div class="ch"><span class="ch-title">Promedio por Bloque</span></div><div class="cp">${barH}</div></div>
    <div class="card"><div class="ch"><span class="ch-title">Tabla de Calificaciones</span></div>${stbl}</div>
  </div>
  <div class="card report-export-keep" style="margin-top:16px;"><div class="ch"><span class="ch-title">Resumen anual por estudiante</span></div><div class="cp">${annual}</div></div>
  </div>
  `;
};

